// Processar dados do Apify
const apifyData = $input.first().json;
const body = $items('Webhook')[0].json.body;

// Extrair métricas principais
const profile = apifyData[0] || {};
const posts = profile.latestPosts || [];

// Calcular métricas
const totalLikes = posts.reduce((sum, p) => sum + (p.likesCount || 0), 0);
const totalComments = posts.reduce((sum, p) => sum + (p.commentsCount || 0), 0);
const avgEngagement = posts.length > 0 ? ((totalLikes + totalComments) / posts.length / profile.followersCount * 100).toFixed(2) : 0;

// Top posts por engajamento
const topPosts = posts
  .sort((a, b) => (b.likesCount + b.commentsCount) - (a.likesCount + a.commentsCount))
  .slice(0, 5)
  .map(p => ({
    caption: p.caption?.substring(0, 100) || '',
    likes: p.likesCount,
    comments: p.commentsCount,
    type: p.type,
    url: p.url
  }));

return [{
  json: {
    concorrente: body.concorrente,
    handle: body.handle,
    metricas: {
      seguidores: profile.followersCount,
      seguindo: profile.followsCount,
      posts: profile.postsCount,
      taxaEngajamento: avgEngagement + '%',
      mediaLikes: Math.round(totalLikes / posts.length) || 0,
      mediaComentarios: Math.round(totalComments / posts.length) || 0
    },
    topPosts,
    message: `Analisar concorrente: ${body.concorrente} (@${body.handle}). Seguidores: ${profile.followersCount}. Taxa de engajamento: ${avgEngagement}%. Posts analisados: ${posts.length}`
  }
}];
